import Vue from 'vue'
import VueRouter from 'vue-router'

Vue.use(VueRouter)

// 解决导航栏或者底部导航tabBar中的vue-router在3.0版本以上频繁点击菜单报错的问题
const originalPush = VueRouter.prototype.push
VueRouter.prototype.push = function push(location) {
  return originalPush.call(this, location).catch(err => err)
}

const routes = [
  // 管理员后台路由
  {
    path: '/manager',
    name: 'Manager',
    component: () => import('../views/manager/Layout.vue'),
    redirect: '/manager/home',
    meta: { requireAuth: true, role: 'ADMIN' },
    children: [
      {
        path: 'home',
        name: 'ManagerHome',
        component: () => import('../views/manager/Home.vue'),
        meta: { name: '系统首页', requireAuth: true, role: 'ADMIN' }
      },
      {
        path: 'person',
        name: 'ManagerPerson',
        component: () => import('../views/manager/Person.vue'),
        meta: { name: '个人信息', requireAuth: true, role: 'ADMIN' }
      },
      {
        path: 'user',
        name: 'UserManage',
        component: () => import('../views/manager/User.vue'),
        meta: { name: '用户管理', requireAuth: true, role: 'ADMIN' }
      },
      {
        path: 'textbook-category',
        name: 'TextbookCategoryManage',
        component: () => import('../views/manager/TextbookCategory.vue'),
        meta: { name: '教材分类管理', requireAuth: true, role: 'ADMIN' }
      },
      {
        path: 'textbook',
        name: 'TextbookManage',
        component: () => import('../views/manager/Textbook.vue'),
        meta: { name: '教材信息管理', requireAuth: true, role: 'ADMIN' }
      },
      {
        path: 'textbook-application',
        name: 'TextbookApplicationManage',
        component: () => import('../views/manager/TextbookApplication.vue'),
        meta: { name: '教材申报管理', requireAuth: true, role: 'ADMIN' }
      },
      {
        path: 'notice',
        name: 'NoticeManage',
        component: () => import('../views/manager/Notice.vue'),
        meta: { name: '公告管理', requireAuth: true, role: 'ADMIN' }
      }
    ]
  },

  // 前台用户路由
  {
    path: '/front',
    name: 'Front',
    component: () => import('../views/front/Layout.vue'),
    redirect: '/front/home',
    meta: { requireAuth: true, role: 'USER' },
    children: [
      {
        path: 'home',
        name: 'FrontHome',
        component: () => import('../views/front/Home.vue'),
        meta: { name: '首页', requireAuth: true, role: 'USER' }
      },
      {
        path: 'person',
        name: 'FrontPerson',
        component: () => import('../views/front/Person.vue'),
        meta: { name: '个人信息', requireAuth: true, role: 'USER' }
      },
      {
        path: 'textbooks',
        name: 'FrontTextbooks',
        component: () => import('../views/front/Textbooks.vue'),
        meta: { name: '教材浏览', requireAuth: true, role: 'USER' }
      },
      {
        path: 'textbook-application',
        name: 'FrontTextbookApplication',
        component: () => import('../views/front/TextbookApplication.vue'),
        meta: { name: '教材申报', requireAuth: true, role: 'USER' }
      },
      {
        path: 'notice',
        name: 'FrontNotice',
        component: () => import('../views/front/Notice.vue'),
        meta: { name: '通知公告', requireAuth: true, role: 'USER' }
      },
      {
        path: 'notice/:id',
        name: 'FrontNoticeDetail',
        component: () => import('../views/front/Notice.vue'),
        meta: { name: '公告详情', requireAuth: true, role: 'USER' }
      },
      {
        path: 'chat',
        name: 'FrontChat',
        component: () => import('../views/front/Chat.vue'),
        meta: { name: 'AI智能助手', requireAuth: true, role: 'USER' }
      }
    ]
  },

  // 教师路由
  {
    path: '/teacher',
    name: 'Teacher',
    component: () => import('../views/teacher/Layout.vue'),
    redirect: '/teacher/home',
    meta: { requireAuth: true, role: 'TEACHER' },
    children: [
      {
        path: 'home',
        name: 'TeacherHome',
        component: () => import('../views/teacher/Home.vue'),
        meta: { name: '系统首页', requireAuth: true, role: 'TEACHER' }
      },
      {
        path: 'person',
        name: 'TeacherPerson',
        component: () => import('../views/teacher/Person.vue'),
        meta: { name: '个人信息', requireAuth: true, role: 'TEACHER' }
      }
    ]
  },

  // 公共路由
  {
    path: '/login',
    name: 'Login',
    component: () => import('../views/Login.vue')
  },
  {
    path: '/register',
    name: 'Register',
    component: () => import('../views/Register.vue')
  },
  {
    path: '/',
    redirect: '/login'
  },
  {
    path: '*',
    name: 'NotFound',
    component: () => import('../views/NotFound.vue')
  }
]

const router = new VueRouter({
  mode: 'history',
  base: process.env.BASE_URL,
  routes
})

// 全局路由守卫，判断是否需要登录权限，以及权限是否满足
router.beforeEach((to, from, next) => {
  console.log('路由跳转:', from.path, '->', to.path);
  
  // 如果需要认证
  if (to.meta.requireAuth) {
    // 获取本地存储的用户信息
    const userInfoStr = localStorage.getItem('xm-user');
    if (!userInfoStr) {
      console.log('未登录，跳转到登录页');
      next('/login');
      return;
    }
    
    // 解析用户信息，检查角色
    const userInfo = JSON.parse(userInfoStr);
    if (!userInfo.token) {
      console.log('token不存在，跳转到登录页');
      next('/login');
      return;
    }
    
    // 如果路由有角色要求，判断用户角色是否匹配
    if (to.meta.role && to.meta.role !== userInfo.role) {
      console.log('角色不匹配，跳转到对应角色的首页');
      
      // 根据用户角色跳转到对应的首页
      switch (userInfo.role) {
        case 'ADMIN':
          next('/manager/home');
          break;
        case 'USER':
          next('/front/home');
          break;
        case 'TEACHER':
          next('/teacher/home');
          break;
        default:
          next('/login');
          break;
      }
      return;
    }
  }
  
  // 放行
  next();
})

export default router
